tasks.command:
$drives = Get-PSDrive -PSProvider FileSystem | Select-Object -ExpandProperty Root
$found = @()
foreach ($drive in $drives) {
  foreach ($sp in @("${drive}Unedited Videos","${drive}unedited videos","${drive}Videos")) {
    if (Test-Path $sp) {
      $files = Get-ChildItem -Path $sp -Recurse -Include *.mp4,*.mov,*.avi,*.mkv,*.mts,*.m2ts -ErrorAction SilentlyContinue | Where-Object { $_.Name -match "(?i)judas|hammer" }
      foreach ($f in $files) { $found += $f.FullName }
    }
  }
}
if ($found.Count -eq 0) {
  foreach ($drive in $drives) {
    try {
      $files = Get-ChildItem -Path $drive -Recurse -Include *.mp4,*.mov,*.avi,*.mkv,*.mts,*.m2ts -ErrorAction SilentlyContinue -Depth 6 | Where-Object { $_.Name -match "(?i)judas|hammer" }
      foreach ($f in $files) { $found += $f.FullName }
    } catch {}
  }
}
Write-Output ("DRIVES: " + ($drives -join ", "))
Write-Output ("FOUND_FILES: " + ($found -join "|"))
Write-Output ("COUNT: " + $found.Count)

$ironEditPaths = @("C:\Users\Ashle\IronEdit","C:\Users\Ashle\Desktop\IronEdit","C:\IronEdit")
$found = $null
foreach ($p in $ironEditPaths) { if (Test-Path $p) { $found = $p; break } }
if ($found) {
  Write-Output ("IRONEDIT_PATH: " + $found)
  $exeFiles = Get-ChildItem -Path $found -Include *.exe -Recurse -ErrorAction SilentlyContinue | Select-Object -First 1
  if ($exeFiles) {
    $WshShell = New-Object -ComObject WScript.Shell
    $Shortcut = $WshShell.CreateShortcut("C:\Users\Ashle\Desktop\IronEdit.lnk")
    $Shortcut.TargetPath = $exeFiles.FullName
    $Shortcut.WorkingDirectory = $found
    $Shortcut.Description = "IronEdit - AI Video Editor"
    $Shortcut.Save()
    Write-Output "SHORTCUT_CREATED: C:\Users\Ashle\Desktop\IronEdit.lnk"
  } else {
    Write-Output "IRONEDIT_STATUS: Found source only. Run npm install && npm start"
  }
} else {
  Write-Output "IRONEDIT_STATUS: Not found in standard locations"
}
